import{_ as r,o as t,c as i,a2 as a}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"Chapter 13: Multi-Provider Support","description":"Abstracting LLM providers behind a common trait to support Anthropic, OpenAI, and local models with seamless switching and fallback.","frontmatter":{"title":"Chapter 13: Multi-Provider Support","description":"Abstracting LLM providers behind a common trait to support Anthropic, OpenAI, and local models with seamless switching and fallback."},"headers":[],"relativePath":"learn/project/13-multi-provider-support/index.md","filePath":"learn/project/13-multi-provider-support/index.md"}'),o={name:"learn/project/13-multi-provider-support/index.md"};function l(s,e,p,n,d,c){return t(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="multi-provider-support" tabindex="-1">Multi-Provider Support <a class="header-anchor" href="#multi-provider-support" aria-label="Permalink to &quot;Multi-Provider Support&quot;">​</a></h1><p>A production coding agent should not be locked to a single LLM provider. Users have different preferences, budgets, and compliance requirements. Some tasks benefit from a more capable model while others need a faster, cheaper one. This chapter builds the provider abstraction layer that lets your agent work with Anthropic&#39;s Claude, OpenAI&#39;s GPT models, and local models through Ollama, all through a unified interface.</p><p>You will start by designing a provider trait that captures the common capabilities across LLM APIs: sending messages, streaming responses, and reporting token usage. Then you will implement concrete adapters for each provider, handling the differences in API formats, authentication, and streaming protocols. The chapter covers model capability detection so the agent knows which features each model supports, runtime model switching for cost optimization, and fallback chains that automatically retry with an alternative provider when one fails.</p><p>Cost tracking rounds out the chapter, giving you visibility into per-request and per-session spending across providers. By the end, your agent will be provider-agnostic at the core, with provider-specific details cleanly encapsulated behind adapter implementations.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Design a provider trait that abstracts away differences between LLM APIs</li><li>Implement adapters for Anthropic, OpenAI, and Ollama with proper streaming support</li><li>Build model capability detection for feature-aware tool and prompt construction</li><li>Create runtime model switching and automatic fallback chains</li><li>Implement cost tracking and token usage reporting across providers</li><li>Test provider adapters with mock servers and recorded responses</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/project/13-multi-provider-support/01-why-multiple-providers.html">Why Multiple Providers</a></li><li><a href="/project/13-multi-provider-support/02-provider-trait.html">Provider Trait</a></li><li><a href="/project/13-multi-provider-support/03-anthropic-adapter.html">Anthropic Adapter</a></li><li><a href="/project/13-multi-provider-support/04-openai-adapter.html">OpenAI Adapter</a></li><li><a href="/project/13-multi-provider-support/05-local-models-ollama.html">Local Models Ollama</a></li><li><a href="/project/13-multi-provider-support/06-model-capabilities.html">Model Capabilities</a></li><li><a href="/project/13-multi-provider-support/07-model-switching.html">Model Switching</a></li><li><a href="/project/13-multi-provider-support/08-fallback-chains.html">Fallback Chains</a></li><li><a href="/project/13-multi-provider-support/09-cost-tracking.html">Cost Tracking</a></li><li><a href="/project/13-multi-provider-support/10-provider-config.html">Provider Config</a></li><li><a href="/project/13-multi-provider-support/11-testing-providers.html">Testing Providers</a></li><li><a href="/project/13-multi-provider-support/12-summary.html">Summary</a></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Chapter 2: API integration patterns and HTTP client usage</li><li>Chapter 7: Streaming response handling and SSE parsing</li><li>Chapter 12: Permission and safety system (the agent you are extending)</li></ul>',10)])])}const m=r(o,[["render",l]]);export{u as __pageData,m as default};
